import { supabaseDataProvider } from "ra-supabase-core";
import {
  withLifecycleCallbacks,
  type DataProvider,
  type GetListParams,
  type Identifier,
  type ResourceCallbacks,
} from "ra-core";
import type {
  ContactNote,
  Deal,
  DealNote,
  RAFile,
  Sale,
  SalesFormData,
  SignUpData,
} from "../../types";
import type { ConfigurationContextValue } from "../../root/ConfigurationContext";
import { ATTACHMENTS_BUCKET } from "../commons/attachments";
import { getIsInitialized } from "./authProvider";
import { getSupabaseClient } from "./supabase";

const getBaseDataProvider = () =>
  supabaseDataProvider({
    instanceUrl: import.meta.env.VITE_SUPABASE_URL,
    apiKey: String(import.meta.env.VITE_SB_PUBLISHABLE_KEY),
    supabaseClient: getSupabaseClient(),
    sortOrder: "asc,desc.nullslast" as any,
  });

const processCompanyLogo = async (params: any) => {
  const logo = params.data.logo;

  if (logo?.rawFile instanceof File) {
    await uploadToBucket(logo);
  }

  return {
    ...params,
    data: {
      ...params.data,
      logo,
    },
  };
};

const getDataProviderWithCustomMethods = () => {
  const baseDataProvider = getBaseDataProvider();

  return {
    ...baseDataProvider,
    async getList(resource: string, params: GetListParams) {
      if (resource === "companies") {
        return baseDataProvider.getList("companies_summary", params);
      }
      if (resource === "contacts") {
        return baseDataProvider.getList("contacts_summary", params);
      }
      if (resource === "activity_log") {
        const { data, total } = await baseDataProvider.getList(
          "activity_log",
          params,
        );
        // Rename snake_case view columns to camelCase to match Activity type
        return {
          data: data.map((row: any) => ({
            ...row,
            contactNote: row.contact_note ?? undefined,
            dealNote: row.deal_note ?? undefined,
            contact_note: undefined,
            deal_note: undefined,
          })),
          total,
        };
      }

      return baseDataProvider.getList(resource, params);
    },
    async getOne(resource: string, params: any) {
      if (resource === "companies") {
        return baseDataProvider.getOne("companies_summary", params);
      }
      if (resource === "contacts") {
        return baseDataProvider.getOne("contacts_summary", params);
      }

      return baseDataProvider.getOne(resource, params);
    },

    async signUp({ email, password, first_name, last_name }: SignUpData) {
      const response = await getSupabaseClient().auth.signUp({
        email,
        password,
        options: {
          data: {
            first_name,
            last_name,
          },
        },
      });

      if (!response.data?.user || response.error) {
        console.error("signUp.error", response.error);
        throw new Error(response?.error?.message || "Failed to create account");
      }

      // Update the is initialized cache
      (getIsInitialized as any)._is_initialized_cache = true;

      return {
        id: response.data.user.id,
        email,
        password,
      };
    },
    async salesCreate(body: SalesFormData) {
      const { data, error } = await getSupabaseClient().functions.invoke<{
        data: Sale;
      }>("users", {
        method: "POST",
        body,
      });

      if (!data || error) {
        console.error("salesCreate.error", error);
        const errorDetails = await (async () => {
          try {
            return (await error?.context?.json()) ?? {};
          } catch {
            return {};
          }
        })();
        throw new Error(errorDetails?.message || "Failed to create the user");
      }

      return data.data;
    },
    async salesUpdate(
      id: Identifier,
      data: Partial<Omit<SalesFormData, "password">>,
    ) {
      const { email, first_name, last_name, administrator, avatar, disabled } =
        data;

      const { data: updatedData, error } =
        await getSupabaseClient().functions.invoke<{
          data: Sale;
        }>("users", {
          method: "PATCH",
          body: {
            sales_id: id,
            email,
            first_name,
            last_name,
            administrator,
            disabled,
            avatar,
          },
        });

      if (!updatedData || error) {
        console.error("salesCreate.error", error);
        throw new Error("Failed to update account manager");
      }

      return updatedData.data;
    },
    async updatePassword(id: Identifier) {
      const { data: passwordUpdated, error } =
        await getSupabaseClient().functions.invoke<boolean>("update_password", {
          method: "PATCH",
          body: {
            sales_id: id,
          },
        });

      if (!passwordUpdated || error) {
        console.error("update_password.error", error);
        throw new Error("Failed to update password");
      }

      return passwordUpdated;
    },
    async unarchiveDeal(deal: Deal) {
      // get all deals where stage is the same as the deal to unarchive
      const { data: deals } = await baseDataProvider.getList<Deal>("deals", {
        filter: { stage: deal.stage },
        pagination: { page: 1, perPage: 1000 },
        sort: { field: "index", order: "ASC" },
      });

      // set index for each deal starting from 1, if the deal to unarchive is found, set its index to the last one
      const updatedDeals = deals.map((d, index) => ({
        ...d,
        index: d.id === deal.id ? 0 : index + 1,
        archived_at: d.id === deal.id ? null : d.archived_at,
      }));

      return await Promise.all(
        updatedDeals.map((updatedDeal) =>
          baseDataProvider.update("deals", {
            id: updatedDeal.id,
            data: updatedDeal,
            previousData: deals.find((d) => d.id === updatedDeal.id),
          }),
        ),
      );
    },
    async isInitialized() {
      return getIsInitialized();
    },
    async mergeContacts(sourceId: Identifier, targetId: Identifier) {
      const { data, error } = await getSupabaseClient().functions.invoke(
        "merge_contacts",
        {
          method: "POST",
          body: { loserId: sourceId, winnerId: targetId },
        },
      );

      if (error) {
        console.error("merge_contacts.error", error);
        throw new Error("Failed to merge contacts");
      }

      return data;
    },
    async promoteIntakeLead(intakeLeadId: Identifier, createDeal = true) {
      const { data, error } = await getSupabaseClient().functions.invoke(
        "promote-intake-lead",
        {
          method: "POST",
          body: { intake_lead_id: intakeLeadId, create_deal: createDeal },
        },
      );

      if (error) {
        console.error("promote-intake-lead.error", error);
        // Preserve structured error from edge function (e.g. 409 already-qualified)
        const message =
          typeof data?.error === "string"
            ? data.error
            : "Failed to promote intake lead";
        throw new Error(message);
      }

      return data;
    },
    async getConfiguration(): Promise<ConfigurationContextValue> {
      const { data } = await baseDataProvider.getOne("configuration", {
        id: 1,
      });
      return (data?.config as ConfigurationContextValue) ?? {};
    },
    async updateConfiguration(
      config: ConfigurationContextValue,
    ): Promise<ConfigurationContextValue> {
      const { data } = await baseDataProvider.update("configuration", {
        id: 1,
        data: { config },
        previousData: { id: 1 },
      });
      return data.config as ConfigurationContextValue;
    },
  } satisfies DataProvider;
};

export type CrmDataProvider = ReturnType<
  typeof getDataProviderWithCustomMethods
>;

const processConfigLogo = async (logo: any): Promise<string> => {
  if (typeof logo === "string") return logo;
  if (logo?.rawFile instanceof File) {
    await uploadToBucket(logo);
    return logo.src;
  }
  return logo?.src ?? "";
};

const lifeCycleCallbacks: ResourceCallbacks[] = [
  {
    resource: "configuration",
    beforeUpdate: async (params) => {
      const config = params.data.config;
      if (config) {
        config.lightModeLogo = await processConfigLogo(config.lightModeLogo);
        config.darkModeLogo = await processConfigLogo(config.darkModeLogo);
      }
      return params;
    },
  },
  {
    resource: "contact_notes",
    beforeSave: async (data: ContactNote, _, __) => {
      if (data.attachments) {
        data.attachments = await Promise.all(
          data.attachments.map((fi) => uploadToBucket(fi)),
        );
      }
      return data;
    },
    afterGetOne: async (result) => {
      if (result.data?.attachments) {
        result.data.attachments = await signAttachmentUrls(
          result.data.attachments,
        );
      }
      return result;
    },
    afterGetList: async (result) => {
      result.data = await Promise.all(
        result.data.map(async (note) => {
          if (note.attachments) {
            note.attachments = await signAttachmentUrls(note.attachments);
          }
          return note;
        }),
      );
      return result;
    },
  },
  {
    resource: "deal_notes",
    beforeSave: async (data: DealNote, _, __) => {
      if (data.attachments) {
        data.attachments = await Promise.all(
          data.attachments.map((fi) => uploadToBucket(fi)),
        );
      }
      return data;
    },
    afterGetOne: async (result) => {
      if (result.data?.attachments) {
        result.data.attachments = await signAttachmentUrls(
          result.data.attachments,
        );
      }
      return result;
    },
    afterGetList: async (result) => {
      result.data = await Promise.all(
        result.data.map(async (note) => {
          if (note.attachments) {
            note.attachments = await signAttachmentUrls(note.attachments);
          }
          return note;
        }),
      );
      return result;
    },
  },
  {
    resource: "sales",
    beforeSave: async (data: Sale, _, __) => {
      if (data.avatar) {
        await uploadToBucket(data.avatar);
      }
      return data;
    },
  },
  {
    resource: "contacts",
    beforeGetList: async (params) => {
      return applyFullTextSearch([
        "first_name",
        "last_name",
        "company_name",
        "title",
        "email",
        "phone",
        "background",
      ])(params);
    },
    afterCreate: async (result) => {
      const tags: number[] | undefined = result.data?.tags;
      if (tags && tags.length > 0) {
        await syncContactTags(result.data.id, tags);
      }
      return result;
    },
    afterUpdate: async (result) => {
      if (result.data?.tags !== undefined) {
        const tags: number[] = result.data.tags ?? [];
        await syncContactTags(result.data.id, tags);
      }
      return result;
    },
  },
  {
    resource: "companies",
    beforeGetList: async (params) => {
      return applyFullTextSearch([
        "name",
        "phone_number",
        "website",
        "zipcode",
        "city",
        "state_abbr",
      ])(params);
    },
    beforeCreate: async (params) => {
      const createParams = await processCompanyLogo(params);

      return {
        ...createParams,
        data: {
          created_at: new Date().toISOString(),
          ...createParams.data,
        },
      };
    },
    beforeUpdate: async (params) => {
      return await processCompanyLogo(params);
    },
  },
  {
    resource: "contacts_summary",
    beforeGetList: async (params) => {
      return applyFullTextSearch(["first_name", "last_name"])(params);
    },
  },
  {
    resource: "deals",
    beforeGetList: async (params) => {
      return applyFullTextSearch(["name", "category", "description"])(params);
    },
    afterCreate: async (result) => {
      const contactIds: number[] | undefined = result.data?.contact_ids;
      if (contactIds && contactIds.length > 0) {
        await syncDealContacts(result.data.id, contactIds);
      }
      return result;
    },
    afterUpdate: async (result) => {
      if (result.data?.contact_ids !== undefined) {
        const contactIds: number[] = result.data.contact_ids ?? [];
        await syncDealContacts(result.data.id, contactIds);
      }
      return result;
    },
    afterGetOne: async (result) => {
      const dealId = result.data?.id;
      if (dealId) {
        const { data: contactIds, error } = await getSupabaseClient()
          .from("deal_contacts")
          .select("contact_id")
          .eq("deal_id", dealId);
        if (!error && contactIds) {
          result.data.contact_ids = contactIds.map((row) => row.contact_id);
        }
      }
      return result;
    },
    afterGetList: async (result) => {
      const dealIds = result.data
        .map((deal: Deal) => deal.id)
        .filter((id): id is number => !!id);
      if (dealIds.length > 0) {
        const { data: dealContacts } = await getSupabaseClient()
          .from("deal_contacts")
          .select("deal_id, contact_id")
          .in("deal_id", dealIds);

        if (dealContacts) {
          const contactMap = new Map<number, number[]>();
          for (const dc of dealContacts) {
            const existing = contactMap.get(dc.deal_id) || [];
            contactMap.set(dc.deal_id, [...existing, dc.contact_id]);
          }
          result.data = result.data.map((deal: Deal) => ({
            ...deal,
            contact_ids: contactMap.get(deal.id as number) ?? [],
          }));
        }
      }
      return result;
    },
  },
];

export const getDataProvider = () => {
  if (import.meta.env.VITE_SUPABASE_URL === undefined) {
    throw new Error("Please set the VITE_SUPABASE_URL environment variable");
  }
  if (import.meta.env.VITE_SB_PUBLISHABLE_KEY === undefined) {
    throw new Error(
      "Please set the VITE_SB_PUBLISHABLE_KEY environment variable",
    );
  }
  return withLifecycleCallbacks(
    getDataProviderWithCustomMethods(),
    lifeCycleCallbacks,
  ) as CrmDataProvider;
};

const applyFullTextSearch = (columns: string[]) => (params: GetListParams) => {
  if (!params.filter?.q) {
    return params;
  }
  const { q, ...filter } = params.filter;
  return {
    ...params,
    filter: {
      ...filter,
      "@or": columns.reduce((acc, column) => {
        if (column === "email")
          return {
            ...acc,
            [`email_fts@ilike`]: q,
          };
        if (column === "phone")
          return {
            ...acc,
            [`phone_fts@ilike`]: q,
          };
        else
          return {
            ...acc,
            [`${column}@ilike`]: q,
          };
      }, {}),
    },
  };
};

const syncDealContacts = async (
  dealId: number,
  contactIds: number[],
): Promise<void> => {
  const { error: deleteError } = await getSupabaseClient()
    .from("deal_contacts")
    .delete()
    .eq("deal_id", dealId);

  if (deleteError) {
    console.error("Failed to delete deal_contacts:", deleteError);
    throw deleteError;
  }

  if (contactIds.length > 0) {
    const { error: insertError } = await getSupabaseClient()
      .from("deal_contacts")
      .insert(
        contactIds.map((contactId) => ({
          deal_id: dealId,
          contact_id: contactId,
        })),
      );

    if (insertError) {
      console.error("Failed to insert deal_contacts:", insertError);
      throw insertError;
    }
  }
};

const syncContactTags = async (
  contactId: number,
  tags: number[],
): Promise<void> => {
  const { error: deleteError } = await getSupabaseClient()
    .from("contact_tags")
    .delete()
    .eq("contact_id", contactId);

  if (deleteError) {
    console.error("Failed to delete contact_tags:", deleteError);
    throw deleteError;
  }

  if (tags.length > 0) {
    const { error: insertError } = await getSupabaseClient()
      .from("contact_tags")
      .insert(tags.map((tagId) => ({ contact_id: contactId, tag_id: tagId })));

    if (insertError) {
      console.error("Failed to insert contact_tags:", insertError);
      throw insertError;
    }
  }
};

const signAttachmentUrls = async (
  attachments: RAFile[] | undefined | null,
): Promise<RAFile[] | undefined | null> => {
  if (!attachments || attachments.length === 0) return attachments;
  return Promise.all(
    attachments.map(async (fi) => {
      if (!fi.path) return fi;
      const { data, error } = await getSupabaseClient()
        .storage.from(ATTACHMENTS_BUCKET)
        .createSignedUrl(fi.path, 3600);
      if (!error && data?.signedUrl) {
        return { ...fi, src: data.signedUrl };
      }
      return fi;
    }),
  );
};

const uploadToBucket = async (fi: RAFile) => {
  if (!fi.src.startsWith("blob:") && !fi.src.startsWith("data:")) {
    // Sign URL check if path exists in the bucket
    if (fi.path) {
      const { error } = await getSupabaseClient()
        .storage.from(ATTACHMENTS_BUCKET)
        .createSignedUrl(fi.path, 60);

      if (!error) {
        return fi;
      }
    }
  }

  const dataContent = fi.src
    ? await fetch(fi.src)
        .then((res) => {
          if (res.status !== 200) {
            return null;
          }
          return res.blob();
        })
        .catch(() => null)
    : fi.rawFile;

  if (dataContent == null) {
    // We weren't able to download the file from its src (e.g. user must be signed in on another website to access it)
    // or the file has no content (not probable)
    // In that case, just return it as is: when trying to download it, users should be redirected to the other website
    // and see they need to be signed in. It will then be their responsibility to upload the file back to the note.
    return fi;
  }

  const file = fi.rawFile;
  const fileParts = file.name.split(".");
  const fileExt = fileParts.length > 1 ? `.${file.name.split(".").pop()}` : "";
  const fileName = `${Math.random()}${fileExt}`;
  const filePath = `${fileName}`;
  const { error: uploadError } = await getSupabaseClient()
    .storage.from(ATTACHMENTS_BUCKET)
    .upload(filePath, dataContent);

  if (uploadError) {
    console.error("uploadError", uploadError);
    throw new Error("Failed to upload attachment");
  }

  const { data: signedData, error: signError } = await getSupabaseClient()
    .storage.from(ATTACHMENTS_BUCKET)
    .createSignedUrl(filePath, 3600); // 1 hour

  if (signError || !signedData?.signedUrl) {
    throw new Error("Failed to create signed URL for attachment");
  }

  fi.path = filePath;
  fi.src = signedData.signedUrl;

  // save MIME type
  const mimeType = file.type;
  fi.type = mimeType;

  return fi;
};
